examples.original_ir:
define i8 @test(i16 %x, i16 %y) {
entry:
  %div = udiv i16 %x, %y
  %or = or i16 %x, %y
  %cmp = icmp ult i16 %or, 256
  br i1 %cmp, label %if.then, label %if.end

if.then:
  %trunc = trunc i16 %div to i8
  ret i8 %trunc

if.end:
  ret i8 0
}

examples.optimized_ir:
define i8 @test(i16 %x, i16 %y) {
entry:
  %0 = trunc i16 %x to i8
  %1 = trunc i16 %y to i8
  %div = udiv i8 %0, %1
  %or = or i16 %x, %y
  %cmp = icmp ult i16 %or, 256
  br i1 %cmp, label %if.then, label %if.end

if.then:
  ret i8 %div

if.end:
  ret i8 0
}
